err = nfp_nsp_wait(nsp);
if (err < 0)
	goto exit_close_nsp;

nfp_nsp_init_ports(pdev, pf, nsp);

pf->nspi = __nfp_nsp_identify(nsp);
if (pf->nspi)
	dev_info(&pdev->dev, "BSP: %s\n", pf->nspi->version);

err = nfp_fw_load(pdev, pf, nsp);
if (err < 0) {
	kfree(pf->nspi);
	kfree(pf->eth_tbl);
	dev_err(&pdev->dev, "Failed to load FW\n");
	goto exit_close_nsp;
}

pf->fw_loaded = !!err;

